14	/* Include files */
15	#include "fpga_base.h"
16	
17	void fpga_base_set_led(uint32_t base_addr, uint8_t val)
18	{
19		Xil_Out8(base_addr + C_LED_OFS, val);
20	}
21	
22	uint8_t fpga_base_read_dip(uint32_t base_addr)
23	{
24		return Xil_In32(base_addr+C_DIP_SW_OFS);
25	}
26	
27	void fpga_base_version(uint32_t base_addr)
28	{
29	   /* Store the year */
30	   Xil_Out32(base_addr + 0x00000018, DATE_YEAR);
31	   /* Store the month */
32	   Xil_Out32(base_addr + 0x0000001C, DATE_MONTH);
33	   /* Store the day */
34	   Xil_Out32(base_addr + 0x00000020, DATE_DAY);
35	   /* Store the hour */
36	   Xil_Out32(base_addr + 0x00000024, TIME_HOUR);
37	   /* Store the minute */
38	   Xil_Out32(base_addr + 0x00000028, TIME_MINUTE);
39	
40	   return;
41	}
42	
43	void fpga_base_print(uint32_t base_addr)
44	{
45	   uint8_t word_addr = 0;
46	   uint8_t byte_index = 0;
47	   uint8_t print_string[17];
48	
49	   /* Print version */
50	   xil_printf("Version: 0x%08X\r\n", Xil_In32(base_addr + C_VERSION_OFS));
51	   /* Print firmware compilation date and time */
52	   xil_printf("FW date/time: %d.%d.%d %02d:%02d\r\n",
53	      Xil_In32(base_addr + C_FW_DATE_YEAR_OFS),
54	      Xil_In32(base_addr + C_FW_DATE_MONTH_OFS),
